&reftitle.parameters;




   character



     A string que terá o primeiro caractere avaliado.

&reftitle.changelog;





    &Version;
    &Description;





    8.5.0

     Passar uma string que não seja um byte único foi descontinuado.

  &reftitle.examples;



    Exemplo de ord


<?php
$str = "\n";
if (ord($str) == 10) {
    echo "O primeiro caractere de \$str é uma nova linha.\n";
}
?>







    Examinando os bytes individuais de uma string UTF-8


<?php
$str = "🐘";
for ( $pos=0; $pos < strlen($str); $pos ++ ) {
 $byte = substr($str, $pos);
 echo 'Byte ' . $pos . ' de $str tem valor ' . ord($byte) . PHP_EOL;
}
?>


    &example.outputs;

Byte 0 de $str tem valor 240
Byte 1 de $str tem valor 159
Byte 2 de $str tem valor 144
Byte 3 de $str tem valor 152
